#include "interface.h"

#include <vector>
#include <cstring>

namespace {

uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}

uint64_t histogram_checksum(const std::vector<uint32_t>& values, uint32_t bins, int iters) {
  std::vector<uint32_t> counts(bins);
  uint64_t hash = 0;

  for (int iter = 0; iter < iters; ++iter) {
    std::memset(counts.data(), 0, bins * sizeof(uint32_t));

    // Accumulate histogram with direct indexing
    for (uint32_t v : values) {
      ++counts[v];
    }

    // Compute checksum
    hash = 1469598103934665603ULL;
    uint32_t b = 0;

    // Unroll by 4 for better throughput
    for (; b + 3 < bins; b += 4) {
      hash = mix(hash, counts[b]);
      hash = mix(hash, counts[b + 1]);
      hash = mix(hash, counts[b + 2]);
      hash = mix(hash, counts[b + 3]);
    }

    // Handle remainder
    for (; b < bins; ++b) {
      hash = mix(hash, counts[b]);
    }
  }

  return hash;
}
